def range_summary(nums):
    if not nums:
        return ''

    nums = sorted(set(nums))
    result = []
    i, n = 0, len(nums)

    while i < n:
        j = i + 1
        while j < n and nums[j] == nums[j - 1] + 1:
            j += 1
        if j - i > 1:
            result.append(f"{nums[i]}-{nums[j-1]}")
        else:
            result.append(str(nums[i]))
        i = j

    return ','.join(result)
